/**
 * Media Upload Component
 * Supports both images and videos with upload functionality
 * Author: generated by Amazon Q
 * Created: 2024-12-22
 */

'use client';

import React, { useState } from 'react';
import { Upload, X, Play } from 'lucide-react';
import { uploadLargeFile } from '@/lib/upload-helper';

interface MediaUploadProps {
  src?: string;
  alt?: string;
  width?: number;
  height?: number;
  className?: string;
  onMediaChange?: (newSrc: string) => void;
  showUploadButton?: boolean;
  uploadButtonText?: string;
  acceptedTypes?: string;
  objectFit?: 'cover' | 'contain' | 'fill' | 'scale-down' | 'none';
  onObjectFitChange?: (objectFit: string) => void;
  showObjectFitControls?: boolean;
}

export function MediaUpload({
  src = '',
  alt = '',
  width = 200,
  height = 120,
  className = '',
  onMediaChange,
  showUploadButton = true,
  uploadButtonText = 'Upload Media',
  acceptedTypes = 'image/*,video/*',
  objectFit = 'fill',
  onObjectFitChange,
  showObjectFitControls = false
}: MediaUploadProps) {
  const [isUploading, setIsUploading] = useState(false);
  const [previewSrc, setPreviewSrc] = useState(src);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [error, setError] = useState<string | null>(null);

  // Update preview when src prop changes
  React.useEffect(() => {
    setPreviewSrc(src);
  }, [src]);

  // Detect if the source is a video
  const isVideo = (url: string) => {
    if (!url) return false;
    const videoExtensions = ['.mp4', '.webm', '.ogg', '.mov', '.avi'];
    return videoExtensions.some(ext => url.toLowerCase().includes(ext)) || 
           url.includes('video/') || 
           url.includes('mp4') || 
           url.includes('webm');
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    // Check file size before upload
    const maxSize = file.type.startsWith('video/') ? 100 * 1024 * 1024 : 10 * 1024 * 1024;
    if (file.size > maxSize) {
      const maxSizeText = file.type.startsWith('video/') ? '100MB' : '10MB';
      setError(`File size too large. Maximum allowed: ${maxSizeText}`);
      return;
    }

    setIsUploading(true);
    setError(null);
    setUploadProgress(0);

    try {
      const result = await uploadLargeFile(file, (progress) => {
        setUploadProgress(progress);
      });

      if (result.error) {
        throw new Error(result.error);
      }

      if (result.url) {
        setPreviewSrc(result.url);
        onMediaChange?.(result.url);
        setUploadProgress(100);
      }
    } catch (error) {
      console.error('Upload error:', error);
      const errorMessage = error instanceof Error ? error.message : 'Upload failed';
      setError(errorMessage);
    } finally {
      setIsUploading(false);
      event.target.value = '';
      setTimeout(() => setUploadProgress(0), 2000);
    }
  };

  const handleRemove = () => {
    setPreviewSrc('');
    onMediaChange?.('');
  };

  const renderMedia = () => {
    if (!previewSrc) {
      return (
        <div 
          className={`flex items-center justify-center bg-gray-100 dark:bg-gray-800 border-2 border-dashed border-gray-300 dark:border-gray-600 rounded-md ${className}`}
          style={{ width, height }}
        >
          <div className="text-center">
            <Upload className="w-8 h-8 text-gray-400 mx-auto mb-2" />
            <p className="text-sm text-gray-500 dark:text-gray-400">No media</p>
          </div>
        </div>
      );
    }

    if (isVideo(previewSrc)) {
      return (
        <div className={`relative ${className}`} style={{ width, height }}>
          <video
            src={previewSrc}
            className={`w-full h-full object-${objectFit} rounded-md`}
            controls
            preload="metadata"
          />
          <div className="absolute top-2 right-2">
            <button
              onClick={handleRemove}
              className="p-1 bg-red-500 text-white rounded-full hover:bg-red-600 transition-colors"
              title="Remove video"
            >
              <X className="w-3 h-3" />
            </button>
          </div>
          <div className="absolute bottom-2 left-2 bg-black bg-opacity-50 text-white px-2 py-1 rounded text-xs">
            Video
          </div>
        </div>
      );
    }

    return (
      <div className={`relative ${className}`} style={{ width, height }}>
        <img
          src={previewSrc}
          alt={alt}
          className={`w-full h-full object-${objectFit} rounded-md`}
        />
        <div className="absolute top-2 right-2">
          <button
            onClick={handleRemove}
            className="p-1 bg-red-500 text-white rounded-full hover:bg-red-600 transition-colors"
            title="Remove image"
          >
            <X className="w-3 h-3" />
          </button>
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-2">
      {renderMedia()}
      
      {/* Error Message */}
      {error && (
        <div className="p-2 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded text-xs text-red-600 dark:text-red-400">
          {error}
        </div>
      )}
      
      {/* Upload Progress */}
      {isUploading && uploadProgress > 0 && (
        <div className="space-y-1">
          <div className="flex justify-between text-xs text-gray-600 dark:text-gray-400">
            <span>Uploading...</span>
            <span>{uploadProgress}%</span>
          </div>
          <div className="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-2 overflow-hidden">
            <div 
              className="bg-blue-600 h-full transition-all duration-300 ease-out"
              style={{ width: `${uploadProgress}%` }}
            />
          </div>
        </div>
      )}
      
      {showObjectFitControls && previewSrc && (
        <div className="space-y-2">
          <label className="block text-xs font-medium text-gray-600 dark:text-gray-400">
            Display Mode
          </label>
          <select
            value={objectFit}
            onChange={(e) => onObjectFitChange?.(e.target.value)}
            className="w-full px-2 py-1 text-xs border border-gray-300 dark:border-gray-600 rounded bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
          >
            <option value="fill">Fill (stretch to fit)</option>
            <option value="cover">Cover (crop to fit)</option>
            <option value="contain">Contain (fit inside)</option>
            <option value="scale-down">Scale Down</option>
            <option value="none">None (original size)</option>
          </select>
        </div>
      )}
      
      {showUploadButton && (
        <div className="flex items-center gap-2">
          <label className="cursor-pointer">
            <input
              type="file"
              accept={acceptedTypes}
              onChange={handleFileUpload}
              className="hidden"
              disabled={isUploading}
            />
            <div className={`flex items-center gap-2 px-3 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 transition-colors text-sm ${
              isUploading ? 'opacity-50 cursor-not-allowed' : ''
            }`}>
              <Upload className="w-4 h-4" />
              {isUploading ? `Uploading... ${uploadProgress}%` : uploadButtonText}
            </div>
          </label>
          
          {previewSrc && (
            <button
              onClick={handleRemove}
              className="px-3 py-2 bg-red-600 text-white rounded-md hover:bg-red-700 transition-colors text-sm"
              disabled={isUploading}
            >
              Remove
            </button>
          )}
        </div>
      )}
    </div>
  );
}